events.text:
@font-face {
  font-family: "GRADE-quality";
  src: url();
  src: url('https://gradepro.org/fonts/GRADE-quality.eot');
  src: url('https://gradepro.org/fonts/GRADE-quality.eot?#iefix')
      format('embedded-opentype'),
    url('https://gradepro.org/fonts/GRADE-quality.woff') format('woff'),
    url('https://gradepro.org/fonts/GRADE-quality.ttf') format('truetype'),
    url('https://gradepro.org/fonts/GRADE-quality.svg#GRADE-quality')
      format('svg');
  font-weight: normal;
  font-style: normal;
}

@media print {
  @page {
    size: portrait;




  }
}

body {
  -webkit-print-color-adjust:exact;
  font: normal 8pt 'Arial Narrow', Arial, sans-serif;
  font-stretch: condensed;
  color: black;
  padding:5px;
  margin:0;
}

sup span.underline {
  margin: 0;
  padding: 0;
  text-decoration: underline;
}

p {
  margin: 0px;
}

ol {
  padding-left:15px;
}

span.bold {
  font-weight: bold;
}

span.cell-value.normal {
  font-weight: normal;
}

span.cell-value.pt8 {
  font-size: 8pt;
}

span.label,
span.cell {
  font-weight: normal;
}

span.block.bold {
  display: block;
  font-weight: bold;
}

span.outcome-name {
  font-size: 9pt;
  margin-top: 5px;
}

span.cell-value {
  min-height: 30px;
  max-width: 250px;
  font-size: 9pt;
}

span.short-name {
  font-weight: normal;
}

table {
  border-spacing: 0;
  border-collapse: collapse;
  font: normal 8pt 'Arial Narrow', Arial, sans-serif;
  width: 100%;
}

thead, tfoot { display: table-row-group }

tr {
  page-break-inside: avoid !important;
}

td {
  text-align: left;
  border-top: solid 1px black;
  border-bottom: solid 1px black;
  border-left: 0px;
  border-right: 0px;
  word-wrap: break-word;
}

th {
  position: relative;
  text-align: left;
  vertical-align: top;
}

th.grey-cell {
  border-top: 1px solid #efefef;
  border-right: 1px solid #efefef;
  background: #e0e0e0;
}

thead,
tbody {
  border-bottom: solid 2px black;
}

.first-letter:first-letter {
  text-transform: uppercase;
 }

.blue-cell {
  text-align: left;
  color: #fff;
  font-weight: normal;
  background-color: #3271aa;
  border-right: 1px solid #efefef;
}

.narrative-desc,
.corresponding-risk,
.grey-cell,
.control,
.absolute-effect {
  vertical-align: top;
  text-align: left;
  background-color: #ebebeb;
}

.white-cell {
  background-color: #ffffff;
}

td.title-cell{
  border: none;
}

td.info-cell {
  border-top: solid 2px black;
  border-bottom: solid 2px black;
  border-left: 0px;
  border-right: 0px;
}

td.control-label {
  background: #e0e0e0;
  border-color: #000000;
  font-weight: bold;
}

p.sof-title {
  font-size: 11pt;
}

p span{
  font-weight: normal;
}

.not-editable-cell,
.normal-font {
  font-weight: normal;
}

.outcome-label-row {
  border: none;
}
.outcome-edit-block {
  display: none;
}
.outcomes-table .outcome-label span {
  margin: 0px 5px;
}

td.outcome-cell,
td.relative-effect,
td.no-of-participants,
td.quality,
td.comments {
  vertical-align: top;
}

td.outcome-cell,
td.control,
td.absolute-effect,
td.relative-effect {
  font-weight: normal;
}

td.outcome-cell {
  max-width: 220px;
}

td.quality {
  width: 75px;
}

.cell-footnotes {
  font-style: italic;
  float: right;
  padding: 2px;
}

.quality-sign {
    font-family: 'GRADE-quality', Cambria, Helvetica, Arial;
    font-size: 14px;
}

.control {
  width: 12%
}
.with-intervention,
.without-intervention,
.difference,
.risk-difference-with-intervention,
.risk-with-control,
.corresponding-risk,
.relative-effect,
.no-of-participants {
  width: 12%
}
.what_happens,
.comments {
  width: 26%
}
.impact {
  width: 36%
}
